export const questionBank = {
  Biology: biology,
  Chemistry: chemistry,
  Physics: physics,
  English: english,
  "Lekki Headmaster": lekkiHeadmaster,
};

function shuffleArray<T>(array: T[]): T[] {
  const shuffled = [...array];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  return shuffled;
}

export function getRandomQuestions(subject: string, count: number): Question[] {
  const pool = questionBank[subject as keyof typeof questionBank];
  if (!pool) return [];
  const shuffled = shuffleArray(pool);
  return shuffled.slice(0, Math.min(count, shuffled.length));
}

export function generateEnglishQuestions(): Question[] {
  const englishQs = shuffleArray(english).slice(0, 50);
  const lekkiQs = shuffleArray(lekkiHeadmaster).slice(0, 10);
  return shuffleArray([...englishQs, ...lekkiQs]);
}

export function generateExamSession(subjects: string[]): Record<string, Question[]> {
  const session: Record<string, Question[]> = {};
  for (const subject of subjects) {
    if (subject === "English") {
      session[subject] = generateEnglishQuestions();
    } else {
      session[subject] = getRandomQuestions(subject, 40);
    }
  }
  return session;
}

export const EXAM_SUBJECTS = ["English", "Biology", "Chemistry", "Physics"] as const;
export type SubjectName = (typeof EXAM_SUBJECTS)[number];
